# ============================================================
# ollama 调用
# ============================================================

def call_ollama(prompt, max_retries=2, timeout=180):
    for attempt in range(max_retries + 1):
        try:
            resp = requests.post(
                OLLAMA_URL,
                json={
                    "model": MODEL,
                    "messages": [{"role": "user", "content": prompt}],
                    "stream": False,
                    "options": {"temperature": 0.7, "num_predict": 4096},
                },
                timeout=timeout,
            )
            resp.raise_for_status()
            content = resp.json()["message"]["content"]
            # 去掉 <think> 标签
            if "<think>" in content:
                content = content.split("</think>")[-1].strip()
            return content
        except Exception as e:
            if attempt < max_retries:
                print(f"  重试 ({attempt+1}/{max_retries}): {e}")
                time.sleep(3)
            else:
                print(f"  调用失败: {e}")
                return None


def parse_generated_qa(text):
    """从 ollama 输出中提取多个 JSON 问答对"""
    if not text:
        return []

    results = []
    # 去掉 markdown code block
    if "```json" in text:
        text = text.split("```json")[1].split("```")[0].strip()
    elif "```" in text:
        parts = text.split("```")
        for i in range(1, len(parts), 2):
            text = parts[i]
            break

    # 尝试解析 JSON 数组
    text = text.strip()
    if text.startswith("["):
        try:
            arr = json.loads(text)
            for obj in arr:
                if isinstance(obj, dict) and "question" in obj and "answer" in obj:
                    if len(obj["answer"]) > 100 and any(c.isdigit() for c in obj["answer"]):
                        results.append(obj)
            return results
        except json.JSONDecodeError:
            pass

    # 尝试逐个提取 JSON 对象
    idx = 0
    while idx < len(text):
        start = text.find("{", idx)
        if start < 0:
            break
        # 找匹配的 }
        depth = 0
        end = start
        for j in range(start, len(text)):
            if text[j] == "{":
                depth += 1
            elif text[j] == "}":
                depth -= 1
                if depth == 0:
                    end = j + 1
                    break
        if depth != 0:
            break
        try:
            obj = json.loads(text[start:end])
            if "question" in obj and "answer" in obj:
                if len(obj["answer"]) > 100 and any(c.isdigit() for c in obj["answer"]):
                    results.append(obj)
        except json.JSONDecodeError:
            pass
        idx = end

    return results


# ============================================================
# 扩展逻辑
# ============================================================

def expand_seeds(category, seeds, target_per_seed=6):
    """用 few-shot 扩展种子题"""
    results = []

    for i, seed in enumerate(seeds):
        # 随机选 2 个同类种子作为 few-shot 示例
        examples = [s for s in seeds if s != seed]
        random.shuffle(examples)
        examples = examples[:2]

        example_text = ""
        for j, ex in enumerate(examples, 1):
            example_text += f'\n示例{j}:\n问题：{ex["q"]}\n回答：{ex["a"]}\n'

        prompt = f"""你是一个量化金融专家。请参考以下{category}领域的问答示例，生成{target_per_seed}个类似但不同的量化计算问答对。

{example_text}

要求：
1. 每个问答对都要包含具体的数字和计算过程
2. 涵盖不同的参数组合和场景
3. 回答要包含详细的计算步骤和数值结果
4. 回答长度至少100字
5. 主题要在{category}范围内但与示例不同

请输出JSON数组格式：
[{{"question": "问题1", "answer": "回答1"}}, {{"question": "问题2", "answer": "回答2"}}, ...]"""

        print(f"  [{category}] 种子 {i+1}/{len(seeds)} 扩展中...", end=" ", flush=True)
        response = call_ollama(prompt, timeout=300)
        qa_list = parse_generated_qa(response)
        results.extend(qa_list)
        print(f"生成 {len(qa_list)} 条")

        time.sleep(1)  # 避免过于频繁

    return results


# ============================================================
# 主流程
# ============================================================

def main():
    print("=" * 60)
    print("量化计算种子题扩展")
    print("=" * 60)

    # 加载进度
    progress = {}
    if os.path.exists(PROGRESS_FILE):
        with open(PROGRESS_FILE, "r") as f:
            progress = json.load(f)
        print(f"加载进度: 已完成 {list(progress.keys())}")

    all_records = []

    # 1. 先加入所有种子题
    seed_count = 0
    for category, seeds in SEEDS.items():
        for seed in seeds:
            record = {
                "messages": [
                    {"role": "system", "content": SYSTEM_PROMPT},
                    {"role": "user", "content": seed["q"]},
                    {"role": "assistant", "content": seed["a"]},
                ],
                "metadata": {"source": "quant_calculations", "category": category, "type": "seed"},
            }
            all_records.append(record)
            seed_count += 1
    print(f"\n种子题: {seed_count} 条")

    # 2. 扩展
    for category, seeds in SEEDS.items():
        if category in progress:
            print(f"\n[{category}] 已完成，跳过")
            # 加载已生成的
            for item in progress[category]:
                record = {
                    "messages": [
                        {"role": "system", "content": SYSTEM_PROMPT},
                        {"role": "user", "content": item["question"]},
                        {"role": "assistant", "content": item["answer"]},
                    ],
                    "metadata": {"source": "quant_calculations", "category": category, "type": "expanded"},
                }
                all_records.append(record)
            continue

        print(f"\n{'='*40}")
        print(f"扩展分类: {category} ({len(seeds)} 种子)")
        expanded = expand_seeds(category, seeds)

        # 保存进度
        progress[category] = [{"question": q["question"], "answer": q["answer"]} for q in expanded]
        with open(PROGRESS_FILE, "w", encoding="utf-8") as f:
            json.dump(progress, f, ensure_ascii=False, indent=2)

        for item in expanded:
            record = {
                "messages": [
                    {"role": "system", "content": SYSTEM_PROMPT},
                    {"role": "user", "content": item["question"]},
                    {"role": "assistant", "content": item["answer"]},
                ],
                "metadata": {"source": "quant_calculations", "category": category, "type": "expanded"},
            }
            all_records.append(record)

        print(f"  {category}: 扩展 {len(expanded)} 条")

    # 3. 写出
    os.makedirs(os.path.dirname(OUTPUT_FILE), exist_ok=True)
    with open(OUTPUT_FILE, "w", encoding="utf-8") as f:
        for r in all_records:
            f.write(json.dumps(r, ensure_ascii=False) + "\n")

    print(f"\n{'='*60}")
    print(f"完成！")
    print(f"  种子题: {seed_count} 条")
    print(f"  扩展题: {len(all_records) - seed_count} 条")
    print(f"  总计: {len(all_records)} 条")
    print(f"  输出: {OUTPUT_FILE}")

    # 分类统计
    from collections import Counter
    cats = Counter()
    for r in all_records:
        cats[r["metadata"]["category"]] += 1
    print(f"\n分类统计:")
    for cat, cnt in sorted(cats.items()):
        print(f"  {cat}: {cnt} 条")


if __name__ == "__main__":
    main()
